// Validate cross-file linking request
const body = $input.first().json.body;

if (!body.user_id || !body.query) {
  throw new Error('Missing required fields: user_id, query');
}

return [{
  json: {
    user_id: body.user_id,
    query: body.query,
    max_results: body.max_results || 20,
    similarity_threshold: body.similarity_threshold || 0.3
  }
}];

// Prepare query embedding for cross-file search
const embeddingRaw = $input.first().json.data || $input.first().json;
const params = $('Validate: Request').first().json;

let embedding;
if (Array.isArray(embeddingRaw) && Array.isArray(embeddingRaw[0])) {
  embedding = embeddingRaw[0];
} else if (Array.isArray(embeddingRaw)) {
  embedding = embeddingRaw;
}

return [{
  json: {
    ...params,
    query_embedding: embedding
  }
}];

// Group results by file and identify common entities
const searchResults = $input.first().json;
const params = $('Validate: Request').first().json;

const results = Array.isArray(searchResults) ? searchResults :
                (searchResults.data ? searchResults.data : [searchResults]);

if (results.length === 0) {
  return [{
    json: {
      skip_llm: true,
      response: {
        success: true,
        query: params.query,
        message: 'No relevant content found across your files.',
        file_groups: [],
        common_entities: [],
        connections: []
      }
    }
  }];
}

// Group results by file
const fileGroups = {};
for (const r of results) {
  const fid = r.file_id || 'unknown';
  if (!fileGroups[fid]) {
    fileGroups[fid] = {
      file_id: fid,
      file_name: r.file_name || 'Unknown',
      chunks: [],
      avg_similarity: 0
    };
  }
  fileGroups[fid].chunks.push({
    content: r.content,
    similarity: r.similarity
  });
}

// Calculate avg similarity per file
for (const fid of Object.keys(fileGroups)) {
  const group = fileGroups[fid];
  group.avg_similarity = group.chunks.reduce((s, c) => s + c.similarity, 0) / group.chunks.length;
  group.avg_similarity = Math.round(group.avg_similarity * 1000) / 1000;
}

// Basic entity extraction across all results
// (Lightweight NER using pattern matching — proper NER would use an LLM)
const allText = results.map(r => r.content).join(' ');

// Extract capitalized multi-word terms (potential named entities)
const entityPattern = /(?:[A-Z][a-z]+(?:\s[A-Z][a-z]+)+)/g;
const rawEntities = allText.match(entityPattern) || [];
const entityCounts = {};
for (const e of rawEntities) {
  const normalized = e.trim();
  if (normalized.length > 3) {
    entityCounts[normalized] = (entityCounts[normalized] || 0) + 1;
  }
}

// Find entities that appear across multiple files
const crossFileEntities = [];
for (const [entity, count] of Object.entries(entityCounts)) {
  if (count >= 2) {
    const filesContaining = Object.entries(fileGroups)
      .filter(([_, g]) => g.chunks.some(c => c.content.includes(entity)))
      .map(([fid, g]) => g.file_name);

    if (filesContaining.length > 1) {
      crossFileEntities.push({
        entity: entity,
        mention_count: count,
        found_in_files: filesContaining
      });
    }
  }
}

crossFileEntities.sort((a, b) => b.found_in_files.length - a.found_in_files.length);

// Build context for LLM analysis
const fileContexts = Object.values(fileGroups)
  .sort((a, b) => b.avg_similarity - a.avg_similarity)
  .map(g => {
    const topChunks = g.chunks
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 3)
      .map(c => c.content)
      .join('\n');
    return `[File: ${g.file_name} | Relevance: ${g.avg_similarity}]\n${topChunks}`;
  })
  .join('\n\n===\n\n');

const filesInvolved = Object.values(fileGroups).map(g => g.file_name);

const prompt = `You are a knowledge synthesis expert. Analyze the following content retrieved from MULTIPLE study files in response to a user query.

USER QUERY: "${params.query}"

FILES INVOLVED: ${filesInvolved.join(', ')}

CROSS-FILE ENTITIES DETECTED: ${crossFileEntities.map(e => e.entity).join(', ') || 'None detected automatically'}

CONTENT FROM EACH FILE:
${fileContexts}

Perform the following analysis and respond with JSON:

1. **Connections**: Identify how information across different files relates to the query and to each other
2. **Common Concepts**: Find shared themes, terminology, or concepts across files
3. **Complementary Info**: Identify where one file fills knowledge gaps left by another
4. **Synthesis**: Create a unified understanding combining insights from all files
5. **Contradictions**: Note any conflicting information between files

JSON format:
{
  "synthesis": "A comprehensive 3-5 sentence answer to the query combining info from all files",
  "connections": [
    {
      "file_a": "filename",
      "file_b": "filename",
      "relationship": "How these files relate on this topic",
      "connection_type": "complementary|overlapping|contradictory|sequential"
    }
  ],
  "common_concepts": [
    {
      "concept": "Shared concept name",
      "files": ["file1", "file2"],
      "description": "How this concept appears across files"
    }
  ],
  "complementary_insights": [
    {
      "gap_in": "filename with gap",
      "filled_by": "filename that fills it",
      "insight": "What additional information is provided"
    }
  ],
  "contradictions": [],
  "study_recommendation": "Recommended order or approach to study these materials together"
}`;

return [{
  json: {
    ...params,
    skip_llm: false,
    file_groups: Object.values(fileGroups),
    cross_file_entities: crossFileEntities.slice(0, 15),
    files_found: filesInvolved.length,
    total_chunks: results.length,
    llm_prompt: prompt
  }
}];

// Format final cross-file linking response
const groqResponse = $input.first().json;
const analysisData = $('Analyze: Entities & Group').first().json;

let llmAnalysis;
try {
  const content = groqResponse.choices[0].message.content;
  llmAnalysis = JSON.parse(content);
} catch (e) {
  llmAnalysis = {
    synthesis: 'Cross-file analysis could not be fully parsed.',
    connections: [],
    common_concepts: [],
    complementary_insights: [],
    contradictions: [],
    study_recommendation: 'Review files individually and note common themes.'
  };
}

return [{
  json: {
    success: true,
    query: analysisData.query,
    files_analyzed: analysisData.files_found,
    total_chunks_matched: analysisData.total_chunks,

    // LLM-powered analysis
    synthesis: llmAnalysis.synthesis,
    connections: llmAnalysis.connections || [],
    common_concepts: llmAnalysis.common_concepts || [],
    complementary_insights: llmAnalysis.complementary_insights || [],
    contradictions: llmAnalysis.contradictions || [],
    study_recommendation: llmAnalysis.study_recommendation || '',

    // Pattern-based entity detection
    cross_file_entities: analysisData.cross_file_entities,

    // File-level summaries
    file_groups: analysisData.file_groups.map(g => ({
      file_id: g.file_id,
      file_name: g.file_name,
      relevance: g.avg_similarity,
      chunks_matched: g.chunks.length
    })),

    analyzed_at: new Date().toISOString()
  }
}];
